import React, { useEffect, useState, useCallback } from 'react';
import {
  Card,
  LinErpListFilterBar,
  localInputToISOWithOffset,
  dispatchAppToast,
} from '@linm-soft-org/linm-web-common-components';
import {
  Title,
  Text,
  Tag,
  Spin,
  Statistic,
} from '@/components/common';
import { useAppDispatch } from '../../../store/hooks';
import { fpcService } from '../../../services/fpc/service';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import type { ConsolidatedPnlDto } from '../../../services/fpc/types';
import styles from './ConsolidatedPnlPage.module.css';

const TEST_ID = 'consolidated-pnl';

const LINE_COLORS: Record<string, string> = {
  REVENUE: 'green',
  COGS: 'red',
  GROSS_MARGIN: 'blue',
  OPEX: 'orange',
  EBITDA: 'purple',
  NET_PROFIT: 'geekblue',
};

const LINE_NAMES: Record<string, string> = {
  REVENUE: 'Doanh thu',
  COGS: 'Giá vốn hàng bán',
  GROSS_MARGIN: 'Lãi gộp',
  OPEX: 'Chi phí hoạt động',
  EBITDA: 'Lợi nhuận trước khấu hao',
  NET_PROFIT: 'Lợi nhuận ròng',
};

interface LineItem {
  lineCode: string;
  lineName: string;
  retailAmount: number;
  onlineAmount: number;
  hqAmount: number;
  membershipAmount: number;
  totalAmount: number;
  planAmount: number;
}

// ── Helpers ──────────────────────────────────────────────

function formatMoney(v: number) {
  return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(v);
}

function isBoldLine(code: string) {
  return code === 'REVENUE' || code === 'NET_PROFIT' || code === 'GROSS_MARGIN';
}

// ── Stat cards ───────────────────────────────────────────

function renderStatCards(d: ConsolidatedPnlDto) {
  return (
    <div className={styles.statsRow}>
      <Card className={styles.statCard}>
        <Statistic
          title="Tổng doanh thu"
          value={d.totalRevenue}
          formatter={(v: any) => formatMoney(Number(v))}
          valueStyle={{ color: '#3f8600' }}
        />
      </Card>
      <Card className={styles.statCard}>
        <Statistic
          title="Giá vốn hàng bán"
          value={d.totalCogs}
          formatter={(v: any) => formatMoney(Number(v))}
          valueStyle={{ color: '#cf1322' }}
        />
      </Card>
      <Card className={styles.statCard}>
        <Statistic
          title="Lãi gộp"
          value={d.totalGrossMargin}
          formatter={(v: any) => formatMoney(Number(v))}
          valueStyle={{ color: d.totalGrossMargin >= 0 ? '#3f8600' : '#cf1322' }}
        />
      </Card>
      <Card className={styles.statCard}>
        <Statistic
          title="Lợi nhuận ròng"
          value={d.netProfit}
          formatter={(v: any) => formatMoney(Number(v))}
          valueStyle={{ color: d.netProfit >= 0 ? '#3f8600' : '#cf1322' }}
        />
      </Card>
    </div>
  );
}

// ── Table — keeps native HTML table (LinReportTable not yet available in common-components) ──

function renderTable(lines: LineItem[]) {
  return (
    <div className={styles.tableWrapper}>
      <table className={styles.table}>
        <thead>
          <tr>
            <th className={styles.thLine}>Chỉ tiêu</th>
            <th className={styles.thAmount}>Bán lẻ</th>
            <th className={styles.thAmount}>Trực tuyến</th>
            <th className={styles.thAmount}>Văn phòng</th>
            <th className={styles.thAmount}>Thành viên</th>
            <th className={styles.thAmount}>Tổng cộng</th>
            <th className={styles.thAmount}>Kế hoạch</th>
          </tr>
        </thead>
        <tbody>
          {lines.map((row) => (
            <tr key={row.lineCode} className={isBoldLine(row.lineCode) ? styles.rowBold : undefined}>
              <td className={styles.tdLine}>
                <div className={styles.lineCell}>
                  {LINE_COLORS[row.lineCode] && (
                    <Tag color={LINE_COLORS[row.lineCode]}>&nbsp;</Tag>
                  )}
                  <Text strong={isBoldLine(row.lineCode)}>
                    {row.lineName || LINE_NAMES[row.lineCode] || row.lineCode}
                  </Text>
                </div>
              </td>
              <td className={styles.tdAmount}>{formatMoney(row.retailAmount)}</td>
              <td className={styles.tdAmount}>{formatMoney(row.onlineAmount)}</td>
              <td className={styles.tdAmount}>{formatMoney(row.hqAmount)}</td>
              <td className={styles.tdAmount}>{formatMoney(row.membershipAmount)}</td>
              <td className={styles.tdAmount}>
                <Text strong>{formatMoney(row.totalAmount)}</Text>
              </td>
              <td className={styles.tdAmount}>{formatMoney(row.planAmount)}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

// ── Page component ───────────────────────────────────────

export default function ConsolidatedPnlPage() {
  const dispatch = useAppDispatch();

  const [data, setData] = useState<ConsolidatedPnlDto | null>(null);
  const [loading, setLoading] = useState(true);

  // ── Date range state (YYYY-MM-DD local) ──
  const [dateRange, setDateRange] = useState<[string, string]>(() => {
    const now = new Date();
    const start = new Date(now.getFullYear(), now.getMonth(), 1);
    const end = new Date(now.getFullYear(), now.getMonth() + 1, 0);
    return [
      start.toISOString().slice(0, 10),
      end.toISOString().slice(0, 10),
    ];
  });

  // ── Search / load data ──
  const handleSearch = useCallback(() => {
    setLoading(true);
    fpcService
      .getConsolidatedPnl({
        periodStart: localInputToISOWithOffset(dateRange[0]),
        periodEnd: localInputToISOWithOffset(dateRange[1]),
      })
      .then((result) => setData(result))
      .catch((err) => {
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Không thể tải báo cáo P&L hợp nhất'),
          type: 'error',
        });
      })
      .finally(() => setLoading(false));
  }, [dateRange, dispatch]);

  // ── Auto-load on first render ──
  useEffect(() => {
    handleSearch();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <div className={styles.page} data-testid={`${TEST_ID}-page`}>
      <Title level={3}>Lợi nhuận và thua lỗ hợp nhất</Title>

      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={dateRange[0]}
        toDate={dateRange[1]}
        onDateChange={(from, to) => {
          setDateRange([from ?? '', to ?? '']);
        }}
        dateLabel="Thời gian"
        expandDateRangeAriaLabel="Chọn khoảng thời gian"
        onSearch={handleSearch}
        searchAriaLabel="Xem báo cáo"
        loading={loading}
      />

      {loading ? (
        <div className={styles.loadingContainer}>
          <Spin size="large" />
        </div>
      ) : data ? (
        <>
          {renderStatCards(data)}
          {renderTable(data.lines)}
        </>
      ) : null}
    </div>
  );
}
